I am having some error with "genvar i"

Vcordic_pipelined.cpp:337:44: error: ‘class Vcordic_pipelined’ has no member named ‘cordic_pipelined__DOT__i’; did you mean ‘cordic_pipelined__DOT__d’?
      vlTOPp->xn = ((0xaU >= (0xfU & vlTOPp->cordic_pipelined__DOT__i))


The following is my verilog source files and my Makefile.

```<code class="text">
`timescale 1ns/100ps

module cordic_pipelined(clk, z0, xn, yn);

  input clk;
  input [10:0] z0;
  output reg [16:0] xn, yn;

  parameter N = 10; // number of iterations

  reg [(N-1):0] d;
  wire [16:0] x [N:0];
  wire [16:0] y [N:0];
  wire [10:0] z [N:0];

  assign x[0] = 'b0_10011_0110_1110_1001;  // 0.60725 in binary
  assign y[0] = 0;
  assign z[0] = z0;

  wire [10:0] arctan [(N-1):0];

  assign arctan[0] = 'b010_1101_0000; // 45.0;
  assign arctan[1] = 'b001_1010_1001; // 26.6;
  assign arctan[2] = 'b000_1110_0000; // 14.0;
  assign arctan[3] = 'b000_0111_0001; // 7.1;
  assign arctan[4] = 'b000_0011_1001; // 3.6;
  assign arctan[5] = 'b000_0001_1100; // 1.8;
  assign arctan[6] = 'b000_0000_1110; // 0.9;
  assign arctan[7] = 'b000_0000_0110; // 0.4;
  assign arctan[8] = 'b000_0000_0011; // 0.2;
  assign arctan[9] = 'b000_0000_0001; // 0.1;

  genvar i;
  generate
     for(i=0; i<N; i=i+1)
       begin: stage_generate
         cordic_stage #(.i(i)) stage_i
         (
           .clk(clk), 
           .x_i(x[i]), .x_o(x[i+1]), 
           .y_i(y[i]), .y_o(y[i+1]), 
           .z_i(z[i]), .z_o(z[i+1]),
           .arctan(arctan[i])
         );
       end
  endgenerate

  genvar j;
  generate
     for(j=0; j<N; j=j+1)
       begin
         always @(*)
           begin
             xn = x[stage_generate[j].i]; // xn = cos(z0)
      		yn = y[stage_generate[j].i]; // yn = sin(z0)
           end
       end
  endgenerate

endmodule
</code>
```

```<code class="text">
`timescale 1ns/100ps

module cordic_stage(clk, x_i, y_i, z_i, x_o, y_o, z_o, arctan);

  input [10:0] arctan;
  parameter i=0;

  input clk;
  input [16:0] x_i, y_i;
  input [10:0] z_i;
  output [16:0] x_o, y_o;
  output [10:0] z_o;

  reg d;
  reg [16:0] x_o, x_next;
  reg [16:0] y_o, y_next;
  reg [10:0] z_o, z_next;

  always @ (posedge clk)
     begin
       x_o <= x_next;
       y_o <= y_next;
       z_o <= z_next; 
     end

  always @(*)
     begin    

       d = (z_i[10] == 0) ? 0 : 1;

       if(d == 0) begin
         x_next = x_i - (y_i >> i);
         y_next = y_i + (x_i >> i);
         z_next = z_i - arctan;
       end

       else begin
         x_next = x_i + (y_i >> i);
         y_next = y_i - (x_i >> i);
         z_next = z_i + arctan;
       end

  end

endmodule
</code>
```


